// Get input data - check your node names match exactly!
const connectionsNode = $input.all().length > 0 ? [] : [];

// Get data from previous nodes
let connections = [];
let stations = [];

try {
  connections = $('Get All Conections').all().map(item => item.json);
} catch(e) {
  try {
    connections = $('Get All Connections').all().map(item => item.json);
  } catch(e2) {
    return [{ json: { error: "Cannot find connections node", details: e2.message }}];
  }
}

try {
  stations = $('Get All Stations').all().map(item => item.json);
} catch(e) {
  return [{ json: { error: "Cannot find stations node", details: e.message }}];
}

const webhookData = $('Webhook').first().json;
const origin = webhookData.body.origin;
const destination = webhookData.body.destination;

// Build adjacency list (graph)
const graph = {};

for (const conn of connections) {
  const from = conn.from_station_id;
  const to = conn.to_station_id;
  const weight = conn.base_time_seconds || 120;

  if (!graph[from]) graph[from] = [];
  if (!graph[to]) graph[to] = [];

  graph[from].push({ station: to, time: weight, line: conn.line_id });
  graph[to].push({ station: from, time: weight, line: conn.line_id });
}

// Debug
const originNeighbors = graph[origin] || [];
const destNeighbors = graph[destination] || [];

// Dijkstra's Algorithm
function dijkstra(start, end) {
  const distances = {};
  const previous = {};
  const lineUsed = {};
  const visited = new Set();
  const queue = [];

  for (const station of Object.keys(graph)) {
    distances[station] = Infinity;
  }
  distances[start] = 0;
  queue.push({ station: start, distance: 0 });

  while (queue.length > 0) {
    queue.sort((a, b) => a.distance - b.distance);
    const current = queue.shift();

    if (visited.has(current.station)) continue;
    visited.add(current.station);

    if (current.station === end) break;

    const neighbors = graph[current.station] || [];
    for (const neighbor of neighbors) {
      if (visited.has(neighbor.station)) continue;

      const newDistance = distances[current.station] + neighbor.time;

      if (newDistance < distances[neighbor.station]) {
        distances[neighbor.station] = newDistance;
        previous[neighbor.station] = current.station;
        lineUsed[neighbor.station] = neighbor.line;
        queue.push({ station: neighbor.station, distance: newDistance });
      }
    }
  }

  const path = [];
  let current = end;

  while (current && current !== start) {
    path.unshift({
      station: current,
      line: lineUsed[current]
    });
    current = previous[current];
  }

  if (current === start) {
    path.unshift({ station: start, line: null });
  }

  return {
    path: path,
    totalTime: distances[end],
    totalMinutes: Math.round(distances[end] / 60)
  };
}

const result = dijkstra(origin, destination);

return [{
  json: {
    debug: {
      connectionsCount: connections.length,
      stationsCount: stations.length,
      originNeighborsCount: originNeighbors.length,
      destNeighborsCount: destNeighbors.length,
      originSample: originNeighbors.slice(0, 3),
      destSample: destNeighbors.slice(0, 3)
    },
    origin: origin,
    destination: destination,
    route: result.path,
    totalSeconds: result.totalTime,
    totalMinutes: result.totalMinutes,
    message: `Route found: ${result.path.length} stations, ${result.totalMinutes} minutes`
  }
}];
